import{c as a,Q as e,j as n,m as o}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"存储(下):NBT 与 Palette 位压缩","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/08-存储下-NBT与Palette位压缩.md","filePath":"minecraftLearning/08-存储下-NBT与Palette位压缩.md","lastUpdated":1781674740000}'),s={name:"minecraftLearning/08-存储下-NBT与Palette位压缩.md"};function i(r,t,l,d,p,c){return e(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="存储-下-nbt-与-palette-位压缩" tabindex="-1">存储(下):NBT 与 Palette 位压缩 <a class="header-anchor" href="#存储-下-nbt-与-palette-位压缩" aria-label="Permalink to &quot;存储(下):NBT 与 Palette 位压缩&quot;">​</a></h1><p>上一篇我们把 Region/Anvil 文件拆到了扇区级别:查位置表 → seek 到扇区 → 读出一段 <code>[长度][压缩类型][压缩数据]</code>。但解压之后那坨字节到底是什么?它怎么表达&quot;这个 chunk 里第几格是什么方块、箱子里装了什么、待处理的水流 tick 有哪些&quot;?</p><p>答案是两层:外层是 <strong>NBT</strong>(一种通用的二进制树格式,序列化几乎所有逐实例数据),内层最关键的是 <strong>Palette 位压缩</strong>(把 4096 个方块压到极小)。这一篇就专讲这两样,并解释为什么它们是 Minecraft &quot;能省则省&quot;的存储基石。</p><blockquote><p>一句话先记住:<strong>NBT 是 Minecraft 万物的序列化语言,Palette 位压缩是体素数据省空间的核心招数;而内存里的方块容器和磁盘上的结构几乎同构,所以加载几乎不用&quot;翻译&quot;。</strong></p></blockquote><hr><h2 id="一、nbt-带类型、带名字、可嵌套的二进制树" tabindex="-1">一、NBT:带类型、带名字、可嵌套的二进制树 <a class="header-anchor" href="#一、nbt-带类型、带名字、可嵌套的二进制树" aria-label="Permalink to &quot;一、NBT:带类型、带名字、可嵌套的二进制树&quot;">​</a></h2><p>NBT 全称 <strong>Named Binary Tag</strong>,是 Notch 早年设计的序列化格式。概念上它就是<strong>二进制版的 JSON</strong>:有对象、有数组、有强类型的标量,可以任意嵌套。但比 JSON 更紧凑、更快,因为它是二进制且自带类型标记。</p><h3 id="每个-tag-的字节布局" tabindex="-1">每个 tag 的字节布局 <a class="header-anchor" href="#每个-tag-的字节布局" aria-label="Permalink to &quot;每个 tag 的字节布局&quot;">​</a></h3><p>一个具名 tag 在字节流里长这样:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ 1 字节:TagType ][ 2 字节:名字长度 ][ N 字节:名字(UTF-8) ][ payload ]</span></span></code></pre></div><ul><li>所有多字节整数都是<strong>大端(big-endian)</strong>。</li><li><code>payload</code> 的长度和结构由 <code>TagType</code> 决定。</li><li>例外:<code>List</code> 内部的元素<strong>没有类型字节、也没有名字</strong>——因为元素类型在 List 头部统一声明了一次,名字对数组元素也没意义。这是解析时最容易写错的地方。</li></ul><h3 id="完整类型表" tabindex="-1">完整类型表 <a class="header-anchor" href="#完整类型表" aria-label="Permalink to &quot;完整类型表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>类型</th><th>payload</th></tr></thead><tbody><tr><td>0</td><td>End</td><td>无(标记一个 Compound 的结束)</td></tr><tr><td>1</td><td>Byte</td><td>1 字节</td></tr><tr><td>2</td><td>Short</td><td>2 字节</td></tr><tr><td>3</td><td>Int</td><td>4 字节</td></tr><tr><td>4</td><td>Long</td><td>8 字节</td></tr><tr><td>5</td><td>Float</td><td>4 字节 IEEE754</td></tr><tr><td>6</td><td>Double</td><td>8 字节 IEEE754</td></tr><tr><td>7</td><td>Byte_Array</td><td>4 字节长度 + N 字节</td></tr><tr><td>8</td><td>String</td><td>2 字节长度 + UTF-8</td></tr><tr><td>9</td><td>List</td><td>1 字节元素类型 + 4 字节个数 + 元素们</td></tr><tr><td>10</td><td>Compound</td><td>一串具名 tag,直到遇到 End(0)</td></tr><tr><td>11</td><td>Int_Array</td><td>4 字节长度 + N×4 字节</td></tr><tr><td>12</td><td>Long_Array</td><td>4 字节长度 + N×8 字节</td></tr></tbody></table><p>两个&quot;容器&quot;类型最关键:</p><ul><li><strong>Compound(10)</strong> ≈ 对象 / 字典:里面是一串具名 tag,<strong>靠一个 End(0)标记收尾</strong>(类似 C 字符串靠 <code>\\0</code> 结尾)。</li><li><strong>List(9)</strong> ≈ 同类型数组:头部先写&quot;元素类型 + 个数&quot;,后面紧跟纯 payload。</li></ul><p>因为这两者能无限嵌套,NBT 天然适合表达 Minecraft 里那种层层套娃的数据:一个 chunk(Compound)里有 <code>sections</code>(List),每个 section 是 Compound,里面又有 <code>block_states</code>(Compound),里面又有 <code>palette</code>(List)和 <code>data</code>(Long_Array)……</p><h3 id="为什么是-nbt-而不是-json-protobuf" tabindex="-1">为什么是 NBT 而不是 JSON/Protobuf <a class="header-anchor" href="#为什么是-nbt-而不是-json-protobuf" aria-label="Permalink to &quot;为什么是 NBT 而不是 JSON/Protobuf&quot;">​</a></h3><ul><li><strong>强类型 + 紧凑</strong>:每个值带 1 字节类型,解析就是顺着字节流递归下降,不用像 JSON 那样边读边猜类型、处理空白和转义,体积也小得多。</li><li><strong>自描述</strong>:带名字,所以新版本加字段、老版本忽略未知字段都很自然,利于演进。</li><li><strong>二进制原生数组</strong>:<code>Byte_Array</code> / <code>Int_Array</code> / <code>Long_Array</code> 直接塞二进制块,正好用来装光照、高度图、调色板位数据这种大块定长数据——这点对体素世界尤其重要。</li></ul><hr><h2 id="二、一个-chunk-的-nbt-长什么样-1-18" tabindex="-1">二、一个 chunk 的 NBT 长什么样(1.18+) <a class="header-anchor" href="#二、一个-chunk-的-nbt-长什么样-1-18" aria-label="Permalink to &quot;二、一个 chunk 的 NBT 长什么样(1.18+)&quot;">​</a></h2><p>解压一个 chunk 的数据,得到的根节点是一个 Compound。现代版本(1.18 之后,世界高度扩展、生物群系下沉到 chunk)里大致有这些字段:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(根 Compound)</span></span>
<span class="line"><span>├── DataVersion        : Int    世界数据版本号(跨版本迁移用)</span></span>
<span class="line"><span>├── xPos / zPos / yPos : Int    chunk 坐标 + 最低 section 的 y</span></span>
<span class="line"><span>├── Status             : String 生成阶段(empty→…→full)</span></span>
<span class="line"><span>├── sections           : List   每个元素是一个 16³ section</span></span>
<span class="line"><span>│     ├── Y            : Byte   该 section 的纵向序号</span></span>
<span class="line"><span>│     ├── block_states : Compound { palette: List, data: Long_Array }</span></span>
<span class="line"><span>│     ├── biomes       : Compound { palette: List, data: Long_Array }(4×4×4 粒度)</span></span>
<span class="line"><span>│     ├── BlockLight   : Byte_Array  每方块 4 bit 的方块光</span></span>
<span class="line"><span>│     └── SkyLight     : Byte_Array  每方块 4 bit 的天空光</span></span>
<span class="line"><span>├── block_entities     : List   箱子物品、告示牌文字、熔炉进度…</span></span>
<span class="line"><span>├── Heightmaps         : Compound 几张高度图,每张是 Long_Array(每列 9 bit)</span></span>
<span class="line"><span>├── block_ticks        : List   还没结算的方块 scheduled tick</span></span>
<span class="line"><span>├── fluid_ticks        : List   还没结算的流体 tick(和方块 tick 分开)</span></span>
<span class="line"><span>├── InhabitedTime      : Long   玩家在此 chunk 累计停留时间(影响刷怪/难度)</span></span>
<span class="line"><span>└── PostProcessing / structures / …</span></span></code></pre></div><p>几个值得注意的点:</p><ul><li><strong><code>Status</code> 是分阶段生成的产物</strong>:地形生成是一条流水线(<code>empty</code> → <code>structure_starts</code> → … → <code>full</code>),跨 chunk 的结构(村庄、洞穴)要求邻居先到某阶段,所以每个 chunk 都记着自己生成到哪一步了。</li><li><strong><code>block_ticks</code> / <code>fluid_ticks</code> 是分开的两条队列</strong>:对应 Tick 系统里方块和流体各自独立的调度。chunk 卸载时,没结算完的延迟任务必须一起持久化,否则水流会&quot;凝固&quot;在半路。</li><li><strong>实体不在这里</strong>:1.17 起,实体被搬到<strong>独立的 <code>entities/</code> region 文件</strong>(POI 兴趣点也单独存 <code>poi/</code>)。把实体和方块分文件,可以在不加载满功能 chunk 的情况下处理它们。</li><li><strong><code>Heightmaps</code> 用 Long_Array 打包</strong>:每个 xz 列存一个高度值,<strong>每列 9 bit</strong>(因为世界高度可达数百格,8 bit 不够),整张图用打包进 long 数组的方式存——这和下面讲的方块调色板是同一套位打包思路。</li></ul><hr><h2 id="三、palette-位压缩-体素数据省空间的核心" tabindex="-1">三、Palette 位压缩:体素数据省空间的核心 <a class="header-anchor" href="#三、palette-位压缩-体素数据省空间的核心" aria-label="Permalink to &quot;三、Palette 位压缩:体素数据省空间的核心&quot;">​</a></h2><p>现在到这一篇真正的重点。一个 section 有 16×16×16 = <strong>4096</strong> 个方块。如果每格都老老实实存一个&quot;全局方块状态 ID&quot;(全游戏两万多个 BlockState,需要约 15 bit),那一个 section 就要 4096×15 ≈ 7.5 KB,几十亿个方块直接把硬盘和内存撑爆。</p><p>但现实是:<strong>一个 section 里通常只有寥寥几种方块</strong>——一片石头、一层泥土、上面全是空气。于是采用<strong>局部调色板(Palette)+ 紧凑位数组</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>palette : [&quot;minecraft:air&quot;, &quot;minecraft:stone&quot;, &quot;minecraft:dirt&quot;, &quot;minecraft:coal_ore&quot;]</span></span>
<span class="line"><span>data    : Long_Array,存 4096 个&quot;在 palette 里的下标&quot;</span></span></code></pre></div><ul><li><strong>palette</strong> 只列出本 section 实际出现过的方块状态,上例只有 4 种。</li><li><strong>data</strong> 的每个格子不存完整 ID,只存&quot;它是 palette 里的第几个&quot;。4 种只需 <strong>2 bit</strong>,而不是 15 bit。</li></ul><h3 id="bitsperentry-规则" tabindex="-1">bitsPerEntry 规则 <a class="header-anchor" href="#bitsperentry-规则" aria-label="Permalink to &quot;bitsPerEntry 规则&quot;">​</a></h3><p>每格用多少位,由调色板大小决定:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bitsPerEntry = max(4, ceil(log2(palette.length)))</span></span></code></pre></div><ul><li>调色板 ≤ 16 种 → 仍按 <strong>4 bit/格</strong>(有个下限 4:再小也不省多少,反而增加碎片处理复杂度)。</li><li>17–32 种 → 5 bit;33–64 种 → 6 bit;以此类推,位宽随种类自动增大。</li><li>当 bitsPerEntry 涨过某个阈值(约 <strong>9 bit</strong>)→ 干脆<strong>放弃局部调色板,直接存全局方块状态 ID</strong>(global palette)。因为种类太多时,维护一张局部调色板本身也不划算了。</li><li><strong>极端退化</strong>:如果整个 section 只有 <strong>1 种</strong>方块(比如全空气、全石头),调色板里就一项,下标永远是 0 ——这时 <strong><code>data</code> 数组可以整个省略</strong>。大片均质地形就靠这一条被压到几乎为零。</li></ul><p>这就是为什么&quot;地下一大片石头&quot;和&quot;天上一大片空气&quot;几乎不占存储:它们各自退化成&quot;调色板单值 + 无 data&quot;。</p><h3 id="反直觉点-压缩率取决于-多样性-而非-方块数" tabindex="-1">反直觉点:压缩率取决于&quot;多样性&quot;而非&quot;方块数&quot; <a class="header-anchor" href="#反直觉点-压缩率取决于-多样性-而非-方块数" aria-label="Permalink to &quot;反直觉点:压缩率取决于&quot;多样性&quot;而非&quot;方块数&quot;&quot;">​</a></h3><p>一个塞满了各种装饰方块、五颜六色的建筑 section,调色板可能有几十上百项,bitsPerEntry 涨到 7、8 位,占用反而比&quot;全是石头&quot;的实心山体大得多。<strong>Minecraft 的存储成本由局部方块种类的多样性决定,不是由&quot;挖没挖空&quot;决定。</strong> 这也解释了为什么高度装饰化的存档体积会显著膨胀。</p><hr><h2 id="四、bit-packing-的版本分水岭" tabindex="-1">四、bit-packing 的版本分水岭 <a class="header-anchor" href="#四、bit-packing-的版本分水岭" aria-label="Permalink to &quot;四、bit-packing 的版本分水岭&quot;">​</a></h2><p>下标怎么塞进 <code>Long_Array</code>(每个 long 64 bit)?这里有一个重要的版本差异,踩坑率极高:</p><h3 id="_1-16-之前-跨界打包-packed" tabindex="-1">1.16 之前:跨界打包(packed) <a class="header-anchor" href="#_1-16-之前-跨界打包-packed" aria-label="Permalink to &quot;1.16 之前:跨界打包(packed)&quot;">​</a></h3><p>bit 紧密首尾相接排列,<strong>一个下标可以横跨两个 long 的边界</strong>。比如 5 bit/格,第 12 个下标占的是前一个 long 的最后几位 + 后一个 long 的开头几位。最省空间,但解析时要处理&quot;跨 long 拼接&quot;,位运算更绕。</p><h3 id="_1-16-及之后-每个-long-内不跨界-padded" tabindex="-1">1.16 及之后:每个 long 内不跨界(padded) <a class="header-anchor" href="#_1-16-及之后-每个-long-内不跨界-padded" aria-label="Permalink to &quot;1.16 及之后:每个 long 内不跨界(padded)&quot;">​</a></h3><p>改成<strong>一个下标绝不跨越 long 边界</strong>。一个 64 位 long 里塞 <code>floor(64 / bitsPerEntry)</code> 个下标,<strong>余下的位直接留空浪费</strong>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>例:bitsPerEntry = 5</span></span>
<span class="line"><span>  每个 long 放 floor(64 / 5) = 12 个下标(12 × 5 = 60 bit)</span></span>
<span class="line"><span>  剩下 64 - 60 = 4 bit 永远空着,浪费掉</span></span></code></pre></div><p>牺牲一点空间(那几个浪费的 bit),换来<strong>解码时不用跨 long 拼接、按位移和掩码就能直接取</strong>,更快也更简单。这是典型的&quot;用空间换时间 + 换实现简洁&quot;。</p><h3 id="读第-i-个方块-1-16-伪代码" tabindex="-1">读第 i 个方块(1.16+ 伪代码) <a class="header-anchor" href="#读第-i-个方块-1-16-伪代码" aria-label="Permalink to &quot;读第 i 个方块(1.16+ 伪代码)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>perLong    = 64 / bitsPerEntry           // 每个 long 装几个下标(向下取整)</span></span>
<span class="line"><span>longIndex  = i / perLong                  // 在第几个 long</span></span>
<span class="line"><span>offset     = (i % perLong) * bitsPerEntry // 在该 long 内的起始位</span></span>
<span class="line"><span>mask       = (1 &lt;&lt; bitsPerEntry) - 1</span></span>
<span class="line"><span>paletteIdx = (data[longIndex] &gt;&gt; offset) &amp; mask</span></span>
<span class="line"><span>blockState = palette[paletteIdx]</span></span></code></pre></div><p>如果是 1.16 之前的存档,<code>longIndex</code>/<code>offset</code> 的计算要按&quot;全局连续 bit 流&quot;来算,并处理跨界——这正是写 <code>.mca</code> 解析器时最容易出 bug 的分支。判断走哪条路径,要看 chunk 的 <strong>DataVersion</strong>(下一节)。</p><hr><h2 id="五、dataversion-与跨版本世界升级" tabindex="-1">五、DataVersion 与跨版本世界升级 <a class="header-anchor" href="#五、dataversion-与跨版本世界升级" aria-label="Permalink to &quot;五、DataVersion 与跨版本世界升级&quot;">​</a></h2><p>每个 chunk(以及 <code>level.dat</code>)都带一个 <strong><code>DataVersion</code></strong>——一个随版本单调递增的整数,记录&quot;这块数据是哪个版本写的&quot;。</p><p>加载时,如果 <code>DataVersion</code> 低于当前游戏版本,Minecraft 会用 <strong>DataFixerUpper</strong>(简称 DFU)这套机制,把旧结构<strong>逐步迁移</strong>到新结构:</p><ul><li>字段改名、嵌套结构调整、方块/物品的 ID 重命名(比如老的数字 ID → 命名空间 ID)、上面讲的 bit-packing 从跨界改成不跨界……都由一连串&quot;data fixer&quot;按版本号顺序套用。</li><li>这就是为什么<strong>很老的存档还能在新版本里打开</strong>:不是靠手工兼容,而是有一条声明式的升级链。</li><li>代价是 DFU 很重、很吃内存,大版本跨度升级一个大世界会明显卡——因为它要把每个 chunk 的 NBT 树整棵走一遍做变换。</li></ul><blockquote><p>把 <code>DataVersion</code> 理解成&quot;数据的 schema 版本号&quot;,DFU 就是&quot;自动迁移脚本集合&quot;。它是 Minecraft 能长期向后兼容的关键基础设施。</p></blockquote><hr><h2 id="六、内存与磁盘同构-为什么加载这么快" tabindex="-1">六、内存与磁盘同构:为什么加载这么快 <a class="header-anchor" href="#六、内存与磁盘同构-为什么加载这么快" aria-label="Permalink to &quot;六、内存与磁盘同构:为什么加载这么快&quot;">​</a></h2><p>最后一个关键设计:<strong>运行时内存里的方块容器,和磁盘上的结构几乎是同一个东西。</strong></p><p>内存里每个 section 用一个 <strong><code>PalettedContainer</code></strong> 持有方块,它内部就是&quot;调色板 + 紧凑位数组&quot;,和我们前面讲的 <code>block_states = { palette, data }</code> 一模一样。于是:</p><ul><li><strong>加载</strong>:NBT 解析出 <code>palette</code> + <code>data</code> → 几乎可以直接搬进 <code>PalettedContainer</code>,不需要把每个方块解包成独立对象再重建。</li><li><strong>存盘</strong>:<code>PalettedContainer</code> 几乎原样序列化回 <code>palette</code> + <code>data</code>。</li><li>运行中方块变化时,<code>PalettedContainer</code> 就地更新:调色板按需增删,bitsPerEntry 自动伸缩(种类变多就扩位重排,变少可压缩)。</li></ul><p>这种&quot;内存结构 = 磁盘结构&quot;的同构设计,省掉了序列化/反序列化里最贵的&quot;对象图重建&quot;,是 Minecraft 能在&quot;无限世界 + 20 TPS&quot;下又快又省的根本原因之一。</p><hr><h2 id="七、串联" tabindex="-1">七、串联 <a class="header-anchor" href="#七、串联" aria-label="Permalink to &quot;七、串联&quot;">​</a></h2><p>把这一篇放回整条存储链路:</p><ul><li><strong>承接上篇(Region/Anvil)</strong>:上一篇负责&quot;在 <code>.mca</code> 文件里按扇区找到一段压缩字节、解压&quot;;这一篇负责解释解压后那棵 <strong>NBT 树</strong>怎么读,以及其中最关键的 <strong>block_states</strong> 怎么用 palette 位压缩表达 4096 个方块。两篇合起来,就是&quot;一个 chunk 从磁盘字节到方块数组&quot;的完整往返。</li><li><strong>呼应渲染篇</strong>:渲染时内存里的 <code>PalettedContainer</code> 和这里磁盘上的 palette 结构同构——存储的省空间技巧和渲染的&quot;只画可见面&quot;,是同一份数据在两端各自的优化,互为对偶。</li><li><strong>呼应生成篇</strong>:<code>Status</code> 字段对应分阶段地形生成;<code>DataVersion</code> 则贯穿整个世界的版本演进。</li></ul><p>一句话收束:<strong>NBT 负责&quot;怎么把任意逐实例数据落成字节&quot;,Palette 位压缩负责&quot;把海量方块压到最小&quot;,DataVersion+DFU 负责&quot;让这些字节跨版本还能读&quot;。</strong> 三者合起来,才撑得住一个可以无限生长、还能十年向后兼容的体素世界。</p>`,66)])])}const h=a(s,[["render",i]]);export{g as __pageData,h as default};
